import '../models/course.dart';import '../models/import_result.dart';import '../datasources/local/database_helper.dart';
class CourseRepository{final DatabaseHelper _db=DatabaseHelper();Future<List<Course>> getAllCourses({int sid=0})=>_db.getAllCourses(sid:sid);Future<List<Course>> getCoursesByDay(int d,{int sid=0})=>_db.getCoursesByDay(d,sid:sid);Future<int> addCourse(Course c)=>_db.insertCourse(c);Future<int> updateCourse(Course c)=>_db.updateCourse(c);Future<int> deleteCourse(int id)=>_db.deleteCourse(id);Future<ImportResult> importCourses(List<Course> c,{int sid=0})async{try{final e=await _db.getAllCourses(sid:sid);final d=<Course>[],n=<Course>[];for(final x in c){final isD=e.any((y)=>y.courseId==x.courseId&&y.dayOfWeek==x.dayOfWeek&&y.startSection==x.startSection);if(isD){d.add(x);}else{n.add(x.copyWith(semesterId:sid));}}if(n.isNotEmpty)await _db.insertCourses(n);return ImportResult.success([...e,...n],d:d.length);}catch(ex){return ImportResult.failure('fail: $ex');}}Future<void> deleteAllCourses({int sid=0})=>_db.deleteAllCourses(sid:sid);}
